import "server-only";

import { get } from "@vercel/edge-config";

export async function getEdgeConfigValue<T>(key: string, fallback: T) {
  const value = await get<T>(key);
  return value ?? fallback;
}

import { NextResponse } from "next/server";

import { getEdgeConfigValue } from "@/lib/vercel/edge-config";

export async function GET() {
  const maintenance = await getEdgeConfigValue("maintenance", false);
  return NextResponse.json({ maintenance });
}

const deployChecks = [
  "Create the vendor project and add production env vars",
  "Run the included smoke route after deploy",
  "Document alerting, retries, and rollback behavior",
];

export default function VercelEdgeConfigPage() {
  return (
    <main className="flex flex-col gap-6 p-6">
      <div>
        <h1 className="text-2xl font-semibold">Vercel Edge Config</h1>
        <p className="text-muted-foreground">Low-latency global reads for flags, maintenance mode, and routing config.</p>
      </div>
      <div className="grid gap-3">
        {deployChecks.map((check) => (
          <div key={check} className="rounded-lg border p-4 text-sm">{check}</div>
        ))}
      </div>
    </main>
  );
}
